// ===============================
// FINAL FRONTEND DASHBOARD (FIXED + STABLE)
// ===============================

// 📦 Setup:
// npx create-react-app frontend
// cd frontend
// npm install axios chart.js react-chartjs-2

import { useState, useEffect } from "react";
import axios from "axios";

// ✅ Chart imports MUST be at top
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend
} from "chart.js";
import { Line } from "react-chartjs-2";

ChartJS.register(CategoryScale, LinearScale, PointElement, LineElement, Title, Tooltip, Legend);

const API = "http://localhost:5000";

export default function App() {
  const [posts, setPosts] = useState([]);
  const [selectedIndex, setSelectedIndex] = useState(null);
  const [status, setStatus] = useState("idle");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  // ✅ FIX: initialize properly
  const [analytics, setAnalytics] = useState([]);
  const [memory, setMemory] = useState(null);

  // ===============================
  // GENERATE POSTS
  // ===============================

  const generatePosts = async () => {
    try {
      setLoading(true);
      setError("");

      const res = await axios.get(`${API}/generate-multiple`);
      setPosts(res.data.posts || []);
      setSelectedIndex(null);
      setStatus("draft");
    } catch (err) {
      setError("❌ Failed to generate posts");
    } finally {
      setLoading(false);
    }
  };

  // ===============================
  // APPROVE + POST
  // ===============================

  const approvePost = async () => {
    if (selectedIndex === null) return alert("Select a post first");

    await axios.post(`${API}/approve`, {
      content: posts[selectedIndex].content,
    });

    setStatus("approved");
  };

  const postNow = async () => {
    if (!window.confirm("Post this to LinkedIn?")) return;

    await axios.post(`${API}/post`);
    alert("✅ Posted successfully");
    setStatus("posted");
    fetchAnalytics();
  };

  // ===============================
  // ANALYTICS
  // ===============================

  const fetchAnalytics = async () => {
    try {
      const res = await axios.get(`${API}/analytics`);
      setAnalytics(res.data || []);
    } catch {
      setAnalytics([]);
    }
  };

  const updateMetrics = async (id) => {
    const likes = prompt("Likes:");
    const comments = prompt("Comments:");
    const impressions = prompt("Impressions:");

    await axios.post(`${API}/update-metrics`, {
      id,
      likes: Number(likes),
      comments: Number(comments),
      impressions: Number(impressions),
    });

    fetchAnalytics();
  };

  // ===============================
  // LEARNING
  // ===============================

  const learn = async () => {
    await axios.post(`${API}/learn`);
    fetchMemory();
  };

  const fetchMemory = async () => {
    const res = await axios.get(`${API}/memory`);
    setMemory(res.data);
  };

  useEffect(() => {
    fetchAnalytics();
    fetchMemory();
  }, []);

  // ===============================
  // SAFE BEST POST (FIX)
  // ===============================

  const bestPost = analytics.length
    ? [...analytics].sort((a, b) => b.engagement - a.engagement)[0]
    : null;

  // ===============================
  // CHART DATA (FIX)
  // ===============================

  const chartData = {
    labels: analytics.map((_, i) => `Post ${i + 1}`),
    datasets: [
      {
        label: "Engagement %",
        data: analytics.map(a => (a.engagement || 0) * 100),
      }
    ]
  };

  // ===============================
  // IMPROVE POST
  // ===============================

  const improvePost = async (index) => {
    const res = await axios.post(`${API}/improve`, {
      content: posts[index].content
    });

    const updated = [...posts];
    updated[index].content = res.data.improved;
    setPosts(updated);
  };

  // ===============================
  // UI
  // ===============================

  return (
    <div style={{ background: "#0f172a", minHeight: "100vh", color: "white", padding: "20px" }}>
      <h1 style={{ fontSize: "28px", marginBottom: "20px" }}>🚀 LinkedIn AI Dashboard</h1>

      <button onClick={generatePosts} style={btnBlue}>
        {loading ? "Generating..." : "Generate 5 Posts"}
      </button>

      {error && <p style={{ color: "red" }}>{error}</p>}

      {/* POSTS */}
      <div style={grid}>
        {posts.map((p, i) => (
          <div key={i} style={{ border: selectedIndex === i ? "2px solid lime" : "1px solid gray", padding: "10px" }}>
            <textarea
              value={p.content}
              onChange={(e) => {
                const updated = [...posts];
                updated[i].content = e.target.value;
                setPosts(updated);
              }}
              style={textarea}
            />

            <div>
              <p>🔥 {p.score?.hook}</p>
              <p>📖 {p.score?.readability}</p>
              <p>🤔 {p.score?.curiosity}</p>
              <p>🧠 {p.score?.personal}</p>
              <p style={{ color: "lime" }}>⭐ {p.score?.total}</p>
            </div>

            <button onClick={() => setSelectedIndex(i)}>Select</button>
            <button onClick={() => improvePost(i)} style={btnPurple}>Improve</button>
          </div>
        ))}
      </div>

      {status === "draft" && <button onClick={approvePost} style={btnYellow}>Approve</button>}
      {status === "approved" && <button onClick={postNow} style={btnGreen}>Post</button>}

      {/* CHART */}
      {analytics.length > 0 && <Line data={chartData} />}

      {/* BEST POST */}
      {bestPost && (
        <div style={card}>
          <h3>🔥 Best Performing</h3>
          <p>{bestPost.content}</p>
        </div>
      )}

      {/* ANALYTICS */}
      <h2>📊 Analytics</h2>
      {analytics.map((a) => (
        <div key={a.id} style={card}>
          <p>{a.content?.slice(0, 100)}...</p>
          <p>👍 {a.metrics?.likes} | 💬 {a.metrics?.comments} | 👀 {a.metrics?.impressions}</p>
          <p style={{ color: "lime" }}>{((a.engagement || 0) * 100).toFixed(2)}%</p>
          <button onClick={() => updateMetrics(a.id)} style={btnPurple}>Update Metrics</button>
        </div>
      ))}

      <button onClick={learn} style={btnRed}>Learn</button>

      {memory && (
        <div style={card}>
          <h3>🧠 Memory</h3>
          <pre>{JSON.stringify(memory, null, 2)}</pre>
        </div>
      )}
    </div>
  );
}

// ===============================
// STYLES
// ===============================

const grid = { display: "grid", gridTemplateColumns: "1fr 1fr", gap: "10px", marginTop: "20px" };
const textarea = { width: "100%", height: "120px", background: "#1e293b", color: "white" };
const card = { background: "#1e293b", padding: "10px", marginTop: "10px" };

const btnBlue = { background: "blue", padding: "10px", marginTop: "10px" };
const btnGreen = { background: "green", padding: "10px", marginTop: "10px" };
const btnYellow = { background: "orange", padding: "10px", marginTop: "10px" };
const btnPurple = { background: "purple", padding: "5px", marginTop: "5px" };
const btnRed = { background: "red", padding: "10px", marginTop: "10px" };

// ===============================
// TEST CASES
// ===============================

// 1. Click Generate → should show 5 posts
// 2. Select post → approve → post
// 3. Update metrics → analytics updates
// 4. Chart should render only if analytics exists
// 5. Improve button rewrites content

// ===============================
// FIX SUMMARY
// ===============================

// ✅ Fixed "analytics is not defined"
// ✅ Moved chart logic inside component
// ✅ Added safety checks for undefined data
// ✅ Fixed improper JSX placement
// ✅ Stabilized rendering

// App now runs without crash ✅
